PROGRAM TankLevelMonitor
VAR_INPUT
    RawLevel      : INT;
    HighAlarmSP   : REAL;
    LowAlarmSP    : REAL;
    Hysteresis    : REAL;
END_VAR
VAR_OUTPUT
    LevelPct      : REAL;
    HighAlarm     : BOOL;
    LowAlarm      : BOOL;
END_VAR

LevelPct := INT_TO_REAL(RawLevel) / 276.48;

IF LevelPct >= HighAlarmSP THEN
    HighAlarm := TRUE;
ELSIF LevelPct < HighAlarmSP - Hysteresis THEN
    HighAlarm := FALSE;
END_IF;

IF LevelPct <= LowAlarmSP THEN
    LowAlarm := TRUE;
ELSIF LevelPct > LowAlarmSP + Hysteresis THEN
    LowAlarm := FALSE;
END_IF;

END_PROGRAM

PROGRAM MotorStarDelta
VAR_INPUT
    startBtn : BOOL;
    stopBtn : BOOL;
    overload : BOOL;
END_VAR

VAR_OUTPUT
    mainContactor : BOOL;
    starContactor : BOOL;
    deltaContactor : BOOL;
    fault : BOOL;
END_VAR

VAR
    startEdge : R_TRIG;
    starTimer : TON;
    bRunning : BOOL;
    bStarPhase : BOOL;
END_VAR

(* Edge detection and timer *)
startEdge(CLK := startBtn);
starTimer(IN := bRunning AND bStarPhase, PT := T#3s);

(* Fault output *)
fault := overload;

(* Stop or Overload reset *)
IF stopBtn OR overload THEN
    bRunning := FALSE;
    bStarPhase := FALSE;
    mainContactor := FALSE;
    starContactor := FALSE;
    deltaContactor := FALSE;
ELSE
    (* Start sequence *)
    IF startEdge.Q AND NOT stopBtn AND NOT overload THEN
        bRunning := TRUE;
        bStarPhase := TRUE;
    END_IF;

    (* Star phase *)
    IF bRunning AND bStarPhase THEN
        mainContactor := TRUE;
        starContactor := TRUE;
        deltaContactor := FALSE;

        IF starTimer.Q THEN
            bStarPhase := FALSE;
        END_IF;
    END_IF;

    (* Delta phase *)
    IF bRunning AND NOT bStarPhase THEN
        mainContactor := TRUE;
        starContactor := FALSE;
        deltaContactor := TRUE;
    END_IF;
END_IF;

END_PROGRAM

TYPE
    ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT);
END_TYPE;

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd : BOOL;
    SensorPresent : BOOL;
    SensorDefect : BOOL;
    EStop : BOOL;
END_VAR;

VAR_OUTPUT
    MotorRun : BOOL;
    RejectSolenoid : BOOL;
END_VAR;

VAR
    state : ConveyorState := ST_IDLE;
    rejectTimer : TON;
END_VAR;

IF EStop THEN
    state := ST_FAULT;
    rejectTimer(IN := FALSE);
ELSE
    CASE state OF
        ST_FAULT:
            state := ST_IDLE;
            rejectTimer(IN := FALSE);
        ST_IDLE:
            IF StartCmd THEN
                state := ST_RUNNING;
            END_IF;
            rejectTimer(IN := FALSE);
        ST_RUNNING:
            IF SensorPresent AND SensorDefect THEN
                state := ST_REJECTING;
                rejectTimer(IN := TRUE, PT := T#500ms);
            ELSE
                rejectTimer(IN := FALSE);
            END_IF;
        ST_REJECTING:
            rejectTimer(IN := TRUE, PT := T#500ms);
            IF rejectTimer.Q THEN
                state := ST_RUNNING;
                rejectTimer(IN := FALSE);
            END_IF;
    END_CASE;
END_IF;

MotorRun := (state = ST_RUNNING);
RejectSolenoid := (state = ST_REJECTING);

END_PROGRAM;

FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    enable : BOOL;
    setpoint : REAL;
    processValue : REAL;
    kp : REAL := 2.0;
    ki : REAL := 0.05;
    kd : REAL := 0.0;
    cycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    output : REAL;
END_VAR
VAR
    integrator : REAL;
    prevError : REAL;
    ts : REAL;
    error : REAL;
    p : REAL;
    i : REAL;
    d : REAL;
END_VAR

ts := TIME_TO_REAL(cycleTime);
error := setpoint - processValue;

IF NOT enable THEN
    output := 0.0;
    integrator := 0.0;
    prevError := 0.0;
ELSE
    p := kp * error;
    integrator := integrator + ki * error * ts;
    d := kd * (error - prevError) / ts;
    output := p + integrator + d;
    prevError := error;
END_IF;

IF output > 100.0 THEN
    output := 100.0;
ELSIF output < 0.0 THEN
    output := 0.0;
END_IF;

END_FUNCTION_BLOCK

PROGRAM PumpLeadLag
VAR_INPUT
  LevelLow : BOOL;
  LevelHigh : BOOL;
  Pump1Fault : BOOL;
  Pump2Fault : BOOL;
  ManualMode : BOOL;
  ManualP1Run : BOOL;
  ManualP2Run : BOOL;
END_VAR
VAR_OUTPUT
  P1Run : BOOL;
  P2Run : BOOL;
END_VAR
VAR
  leadPump : INT := 1;
END_VAR

IF ManualMode THEN
  P1Run := ManualP1Run;
  P2Run := ManualP2Run;
ELSE
  IF leadPump = 1 AND Pump1Fault AND NOT Pump2Fault THEN
    leadPump := 2;
  ELSIF leadPump = 2 AND Pump2Fault AND NOT Pump1Fault THEN
    leadPump := 1;
  END_IF;

  IF LevelHigh THEN
    P1Run := FALSE;
    P2Run := FALSE;
  ELSIF LevelLow THEN
    IF leadPump = 1 THEN
      P1Run := TRUE;
      P2Run := FALSE;
    ELSE
      P1Run := FALSE;
      P2Run := TRUE;
    END_IF;
  END_IF;
END_IF;

END_PROGRAM

PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort : BOOL;
END_VAR

VAR_OUTPUT
    Valve1 : BOOL;
    Valve2 : BOOL;
    Valve3 : BOOL;
    SeqDone : BOOL;
    SeqActive : BOOL;
END_VAR

VAR
    step : INT := 0;
    tmr1 : TON;
    tmr2 : TON;
    tmr3 : TON;
END_VAR

(* Сброс выходов по умолчанию *)
Valve1 := FALSE;
Valve2 := FALSE;
Valve3 := FALSE;
SeqDone := FALSE;
SeqActive := FALSE;

(* Обработка аварийного останова *)
IF Abort THEN
    step := 0;
    tmr1(IN := FALSE);
    tmr2(IN := FALSE);
    tmr3(IN := FALSE);
    RETURN;
END_IF;

CASE step OF
    0:
        SeqDone := FALSE;
        IF StartSeq THEN
            step := 1;
            tmr1(IN := TRUE, PT := T#2s);
        END_IF;
    1:
        SeqActive := TRUE;
        Valve1 := TRUE;
        tmr1(IN := TRUE, PT := T#2s);
        IF tmr1.Q THEN
            step := 2;
            tmr1(IN := FALSE);
            tmr2(IN := TRUE, PT := T#3s);
        END_IF;
    2:
        SeqActive := TRUE;
        Valve2 := TRUE;
        tmr2(IN := TRUE, PT := T#3s);
        IF tmr2.Q THEN
            step := 3;
            tmr2(IN := FALSE);
            tmr3(IN := TRUE, PT := T#1s);
        END_IF;
    3:
        SeqActive := TRUE;
        Valve3 := TRUE;
        tmr3(IN := TRUE, PT := T#1s);
        IF tmr3.Q THEN
            step := 4;
            tmr3(IN := FALSE);
        END_IF;
    4:
        SeqDone := TRUE;
        step := 0;
END_CASE;

END_PROGRAM

PROGRAM SafetyInterlock
VAR_INPUT
    eStopOK : BOOL;
    guardClosed : BOOL;
    resetPB : BOOL;
END_VAR
VAR_OUTPUT
    machineEnable : BOOL;
    safetyFault : BOOL;
END_VAR
VAR
    resetTrig : R_TRIG;
END_VAR

resetTrig(CLK := resetPB);

IF (NOT eStopOK) OR (NOT guardClosed) THEN
    safetyFault := TRUE;
ELSIF resetTrig.Q AND eStopOK AND guardClosed THEN
    safetyFault := FALSE;
END_IF;

machineEnable := NOT safetyFault AND eStopOK AND guardClosed;

END_PROGRAM

PROGRAM ProductionCounter
VAR_INPUT
  productSensor : BOOL;
  resetBatch : BOOL;
  batchTarget : INT := 1000;
END_VAR

VAR_OUTPUT
  batchCount : INT;
  batchComplete : BOOL;
  totalCount : INT;
END_VAR

VAR
  SensorEdge : R_TRIG;
  Counter : CTU;
END_VAR

SensorEdge(CLK := productSensor);
Counter(CU := SensorEdge.Q, R := resetBatch, PV := batchTarget);
batchCount := Counter.CV;
batchComplete := Counter.Q;
IF SensorEdge.Q THEN
  totalCount := totalCount + 1;
END_IF;
END_PROGRAM

FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
END_VAR

IF WindowSize < 1 THEN
    EffectiveSize := 1;
ELSIF WindowSize > 10 THEN
    EffectiveSize := 10;
ELSE
    EffectiveSize := WindowSize;
END_IF;

IF NOT Enable THEN
    Count := 0;
    Head := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSE
    IF Count < EffectiveSize THEN
        Buffer[Head] := RawInput;
        Sum := Sum + RawInput;
        Count := Count + 1;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
        Buffer[Head] := RawInput;
    END_IF;

    Head := (Head + 1) MOD 10;
    Filtered := Sum / INT_TO_REAL(Count);
END_IF;

END_FUNCTION_BLOCK
